syntax = "proto3";
package user;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.user";

service UserService {
  rpc GetUser(GetUserRequest) returns (GetUserResponse);
  rpc GetProfile(GetProfileRequest) returns (GetProfileResponse);
  rpc UpdateProfile(UpdateProfileRequest) returns (UpdateProfileResponse);
  rpc GetRecommendUsers(GetRecommendUsersRequest) returns (GetRecommendUsersResponse);
  rpc GetNearbyUsers(GetNearbyUsersRequest) returns (GetNearbyUsersResponse);
  rpc UpdateLocation(UpdateLocationRequest) returns (UpdateLocationResponse);
  rpc GetMannerScore(GetMannerScoreRequest) returns (GetMannerScoreResponse);
}

message SimpleUser {
  string id = 1;
  string nickname = 2;
  optional string profile_image_url = 3;
  int32 manner_score = 4;
  bool is_online = 5;
}

message UserProfile {
  string id = 1;
  string user_id = 2;
  string nickname = 3;
  string gender = 4;
  string birth_date = 5;
  optional string bio = 6;
  repeated ProfileImage profile_images = 7;
  int32 manner_score = 8;
  bool is_visible = 9;
  int32 followers_count = 10;
  int32 following_count = 11;
  bool is_following = 12;
}

message ProfileImage {
  string id = 1;
  string image_url = 2;
  int32 sort_order = 3;
}

message GetUserRequest { string user_id = 1; }
message GetUserResponse { SimpleUser user = 1; }

message GetProfileRequest {
  string requester_user_id = 1;
  string target_user_id = 2;
}
message GetProfileResponse { UserProfile profile = 1; }

message UpdateProfileRequest {
  string user_id = 1;
  optional string nickname = 2;
  optional string bio = 3;
  optional bool is_visible = 4;
  optional double latitude = 5;
  optional double longitude = 6;
}
message UpdateProfileResponse { UserProfile profile = 1; }

message GetRecommendUsersRequest {
  string user_id = 1;
  int32 limit = 2;
  int32 offset = 3;
}
message GetRecommendUsersResponse { repeated UserProfile users = 1; }

message GetNearbyUsersRequest {
  string user_id = 1;
  double radius_km = 2;
}
message GetNearbyUsersResponse { repeated SimpleUser users = 1; }

message UpdateLocationRequest {
  string user_id = 1;
  double latitude = 2;
  double longitude = 3;
}
message UpdateLocationResponse { bool success = 1; }

message GetMannerScoreRequest { string user_id = 1; }
message GetMannerScoreResponse { int32 manner_score = 1; }
